<?php
namespace StepSystem\Controllers;
use StepSystem\Core\View;use StepSystem\Core\Flash;use StepSystem\Core\Auth;use StepSystem\Core\Database;use StepSystem\Models\User;use StepSystem\Services\Setting;
class AuthController{
 public function register(){$enabled=Setting::get('registration_enabled','1');$days=max(0,(int)Setting::get('registration_gift_days','7'));if($enabled!=='1'){if($_SERVER['REQUEST_METHOD']==='POST')Flash::set('当前暂未开放注册','error');View::render('register',['title'=>'用户注册','registrationEnabled'=>false,'giftDays'=>$days]);}if($_SERVER['REQUEST_METHOD']==='POST'){$n=trim($_POST['username']??'');$p=trim((string)($_POST['password']??''));$p2=$_POST['password2']??'';if(!preg_match('/^[A-Za-z0-9_]{3,32}$/',$n)){Flash::set('用户名只能包含字母、数字、下划线，长度 3-32 位','error');redirect('index.php?r=register');}if(strlen($p)<6||$p!==$p2){Flash::set('密码至少 6 位且两次一致','error');redirect('index.php?r=register');}$expires=$days>0?date('Y-m-d H:i:s',strtotime('+'.$days.' days')):null;try{User::create($n,$p,'user',$expires);Flash::set($days>0?'注册成功，已赠送 '.$days.' 天有效期':'注册成功');redirect('index.php?r=login');}catch(\Throwable $e){Flash::set('用户名已存在','error');redirect('index.php?r=register');}}View::render('register',['title'=>'用户注册','registrationEnabled'=>true,'giftDays'=>$days]);}
 public function login(){if($_SERVER['REQUEST_METHOD']==='POST'){$n=trim($_POST['username']??'');$p=trim((string)($_POST['password']??''));$x=User::findByUsername($n);if(!$x||!password_verify($p,$x['password'])){Flash::set('账号或密码错误','error');redirect('index.php?r=login');}if((int)$x['status']!==1){Flash::set('账号已禁用','error');redirect('index.php?r=login');}if($x['role']!=='admin'&&Auth::expired($x['expires_at'])){Flash::set('账号已到期，请联系管理员续期','error');redirect('index.php?r=login');}Database::pdo()->prepare('UPDATE users SET last_login_at=? WHERE id=?')->execute([now(),$x['id']]);$_SESSION['user']=User::find($x['id']);redirect($x['role']==='admin'?'index.php?r=admin':'index.php?r=dashboard');}View::render('login',['title'=>'登录']);}
 public function logout(){session_destroy();redirect('index.php');}
}